// Get reference to the rapi-doc element
const rapidocEl = document.getElementById('my-api-docs');

// Load a new OpenAPI spec dynamically
rapidocEl.loadSpec('https://api.example.com/openapi.json');

// Listen for spec-loaded event
rapidocEl.addEventListener('spec-loaded', (event) => {
    console.log('Spec loaded:', event.detail);
});

// Listen for before-try event to inject auth token
rapidocEl.addEventListener('before-try', (event) => {
    const request = event.detail.request;
    request.headers.append('Authorization', 'Bearer ' + getAuthToken());
});

// Listen for after-try event to process responses
rapidocEl.addEventListener('after-try', (event) => {
    const response = event.detail.response;
    console.log('Response status:', response.status);
});
